prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?modelName ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:id ?modelId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "3c08e52742754da6a4065fc5787131dc") ||
         CONTAINS(LCASE(STR(?originalId)), "3c08e52742754da6a4065fc5787131dc") ||
         CONTAINS(LCASE(STR(?normalizedId)), "3c08e52742754da6a4065fc5787131dc"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?task ?taskName ?gateway ?gatewayName ?gatewayType ?gatewayDir WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?choreo a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  OPTIONAL {
    ?task tai:belongsTo ?choreo .
    ?task a bboExt:ChoreographyTask .
    OPTIONAL { ?task bbo:name ?taskName . }
  }

  OPTIONAL {
    ?gateway tai:belongsTo ?choreo .
    ?gateway a bboExt:ExclusiveGateway .
    OPTIONAL { ?gateway bbo:name ?gatewayName . }
    OPTIONAL { ?gateway bboExt:gatewayDirection ?gatewayDir . }
  }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?startEvent ?startName ?endEvent ?endName WHERE {
  ?model a bboExt:Model .
