  ?flow1 a bbo:SequenceFlow . ?flow1 tai:belongsTo ?choreo . ?flow1 bbo:has_sourceRef ?start . ?flow1 bbo:has_targetRef ?n1 .
  OPTIONAL { ?n1 bbo:name ?s1 . }

  ?flow2 a bbo:SequenceFlow . ?flow2 tai:belongsTo ?choreo . ?flow2 bbo:has_sourceRef ?n1 . ?flow2 bbo:has_targetRef ?n2 .
