  OPTIONAL { ?n4 bbo:name ?s4 . }

  ?flow5 a bbo:SequenceFlow . ?flow5 tai:belongsTo ?choreo . ?flow5 bbo:has_sourceRef ?n4 . ?flow5 bbo:has_targetRef ?n5 .
  OPTIONAL { ?n5 bbo:name ?s5 . }

  ?flow6 a bbo:SequenceFlow . ?flow6 tai:belongsTo ?choreo . ?flow6 bbo:has_sourceRef ?n5 . ?flow6 bbo:has_targetRef ?n6 .
  OPTIONAL { ?n6 bbo:name ?s6 . }

  ?flow7 a bbo:SequenceFlow . ?flow7 tai:belongsTo ?choreo . ?flow7 bbo:has_sourceRef ?n6 . ?flow7 bbo:has_targetRef ?end .
  OPTIONAL { ?n7 bbo:name ?s7 . }
